﻿"use client";

import { useParams, useRouter } from "next/navigation";
import { RealtimeChat } from "@/components/features/realtime-chat/realtime-chat";
import { useUser } from "@/contexts/UserContext";
import { useMessagesQuery } from "@/hooks/use-messages-query";
import { Navbar } from "@/components/app/navigation/Navbar";
import { Loader2 } from "lucide-react";
import { useEffect, useState, useMemo, useCallback } from "react";
import { createClient } from "@/lib/infra/supabase/supabase";
import { cn } from "@/lib/core/utils/utils";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/shared/ui/avatar";
import { formatDistanceToNow } from "date-fns";
import { it } from "date-fns/locale";

import { Input } from "@/components/shared/ui/input";
import { Button } from "@/components/shared/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/shared/ui/dialog";
import { Search, Plus, MessageSquarePlus, X } from "lucide-react";
import { toast } from "@/lib/domains/notifications";
import { CopyMap } from "@/lib/app/content/copy-system";

type ChatListEntry = {
  userId: string;
  lastMessage: string;
  lastMessageType: string;
  lastMessageTime: string;
  unreadCount: number;
};

export function ChatClient({ copy }: { copy: CopyMap }) {
  const params = useParams();
  const rawUserId = params.id ? (Array.isArray(params.id) ? params.id[0] : params.id) : null;
  const [targetUserId, setTargetUserId] = useState<string | null>(null);
  const [targetUser, setTargetUser] = useState<{
    id: string;
    name: string;
    image?: string | null;
    handle?: string | null;
  } | null>(null);
  const { user, isLoading, role: appRole, isFounder } = useUser();
  const router = useRouter();
  const supabase = useMemo(() => createClient(), []);
  const [recentChats, setRecentChats] = useState<{ 
    userId: string, 
    name: string, 
    avatarUrl: string | null,
    lastMessage: string,
    lastMessageType: string, 
    lastMessageTime: string,
    unreadCount: number,
    deal?: {
      id: string,
      status: string,
      price: number,
      currency?: string,
      lastEvent?: string
    }
  }[]>([]);
  const [loadingChats, setLoadingChats] = useState(true);

  const sidebarCopy = copy['sidebar'] || {};
  const chatCopy = copy['chat'] || {};

  // Resolve rawUserId (UUID or Wallet) to targetUserId (UUID)
  useEffect(() => {
    async function resolveUser() {
        if (!rawUserId) {
            setTargetUserId(null);
            return;
        }

        // If it looks like a UUID, use it directly
        const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
        if (uuidRegex.test(rawUserId)) {
            setTargetUserId(rawUserId);
            return;
        }

        // Security hardening: do not resolve direct chats by wallet/payout address.
        setTargetUserId(null);
    }
    resolveUser();
  }, [rawUserId, supabase]);

  useEffect(() => {
    async function loadTargetUser() {
      if (!targetUserId) {
        setTargetUser(null);
        return;
      }

      const existingChat = recentChats.find((chat) => chat.userId === targetUserId);
      if (existingChat) {
        setTargetUser({
          id: existingChat.userId,
          name: existingChat.name,
          image: existingChat.avatarUrl,
          handle: null,
        });
        return;
      }

      const { data: profile, error } = await supabase
        .from("profiles")
        .select("id, full_name, username, avatar_url")
        .eq("id", targetUserId)
        .maybeSingle();

      if (error || !profile) {
        setTargetUser({
          id: targetUserId,
          name: "Unknown User",
        });
        return;
      }

      setTargetUser({
        id: profile.id,
        name: profile.full_name || profile.username || "Unknown User",
        image: profile.avatar_url,
        handle: profile.username,
      });
    }

    loadTargetUser();
  }, [targetUserId, recentChats, supabase]);

  // Fetch recent chats
  const fetchRecentChats = useCallback(async () => {
    if (!user) return;
    setLoadingChats(true);

    try {
      // Get all unique users we've chatted with
      const { data: messages, error } = await supabase
        .from('messages')
        .select(`
          id,
          content,
          created_at,
          sender_id,
          receiver_id,
          is_read,
          type
        `)
        .or(`sender_id.eq.${user.id},receiver_id.eq.${user.id}`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      // Group by user
      const chatsMap = new Map<string, ChatListEntry>();

      messages?.forEach(msg => {
        const otherUserId = msg.sender_id === user.id ? msg.receiver_id : msg.sender_id;
        if (!chatsMap.has(otherUserId)) {
          chatsMap.set(otherUserId, {
            userId: otherUserId,
            lastMessage: msg.content,
            lastMessageType: msg.type || 'text',
            lastMessageTime: msg.created_at,
            unreadCount: 0
          });
        }

        // Count unread from others
        if (msg.receiver_id === user.id && !msg.is_read) {
          const chat = chatsMap.get(otherUserId);
          if (chat) {
            chat.unreadCount++;
          }
        }
      });

      // Fetch profiles for these users
      const userIds = Array.from(chatsMap.keys());
      if (userIds.length > 0) {
        const { data: profiles } = await supabase
          .from('profiles')
          .select('id, username, full_name, avatar_url')
          .in('id', userIds);

        // Fetch active deals
        const { data: deals } = await supabase
          .from('deals')
          .select('id, status, price, buyer_id, seller_id')
          .or(`buyer_id.in.(${userIds.join(',')}),seller_id.in.(${userIds.join(',')})`)
          .eq('status', 'active'); // Only active deals

        const finalChats = userIds.flatMap(id => {
          const chat = chatsMap.get(id);
          if (!chat) {
            return [];
          }

          const profile = profiles?.find(p => p.id === id);
          const deal = deals?.find(d => (d.buyer_id === id && d.seller_id === user.id) || (d.seller_id === id && d.buyer_id === user.id));

          return [{
            ...chat,
            name: profile?.full_name || profile?.username || "Unknown User",
            avatarUrl: profile?.avatar_url,
            deal: deal ? {
              id: deal.id,
              status: deal.status,
              price: deal.price
            } : undefined
          }];
        });

        setRecentChats(finalChats);
      } else {
        setRecentChats([]);
      }
    } catch (error) {
      console.error("Error fetching chats:", error);
    } finally {
      setLoadingChats(false);
    }
  }, [user, supabase]);

  useEffect(() => {
    fetchRecentChats();

    // Subscribe to new messages to update list
    const channel = supabase
      .channel('chat_list_updates')
      .on('postgres_changes', { 
        event: 'INSERT', 
        schema: 'public', 
        table: 'messages',
        filter: `receiver_id=eq.${user?.id}`
      }, () => {
        fetchRecentChats();
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [fetchRecentChats, user, supabase]);

  if (isLoading) {
    return (
      <div className="h-screen bg-black flex items-center justify-center">
        <Loader2 className="w-8 h-8 text-white animate-spin" />
      </div>
    );
  }

  if (!user) {
    router.push("/auth?next=/inbox");
    return null;
  }

  const roomName = targetUserId ? [user.id, targetUserId].sort().join("_") : null;
  const username =
    user.user_metadata?.username || user.user_metadata?.full_name || user.email || user.id;
  const isVerified = isFounder || appRole === "seller";
  const role = isFounder ? "Admin" : appRole === "seller" ? "Seller" : "Buyer";

  return (
    <div className="flex h-screen bg-black text-white overflow-hidden">
      <Navbar /> {/* This might need adjustment as Navbar is usually at top, but layout might differ for chat app */}
      {/* Actually, Chat page usually has its own layout or hides standard Navbar. 
          Assuming standard layout for now, but often chat is full screen. 
          Let's adjust: typically chat page shouldn't have top navbar if it's a dashboard-like view, 
          or it should be integrated. Based on current file structure, it seems standalone.
      */}

      <div className="flex w-full h-full pt-14"> {/* pt-14 to account for fixed Navbar */}
        {/* Sidebar */}
        <div className={cn(
          "w-full md:w-80 border-r border-white/10 flex flex-col bg-[#1C1C1E]",
          targetUserId ? "hidden md:flex" : "flex"
        )}>
          <div className="p-4 border-b border-white/10 flex justify-between items-center">
            <h1 className="font-bold text-xl">{sidebarCopy.title || "Messages"}</h1>
            {/* New Chat Button */}
            <Dialog>
              <DialogTrigger asChild>
                <Button variant="ghost" size="icon" className="hover:bg-white/10">
                  <MessageSquarePlus className="w-5 h-5" />
                </Button>
              </DialogTrigger>
              <DialogContent className="bg-[#1C1C1E] border-white/10 text-white">
                <DialogHeader>
                  <DialogTitle>New Message</DialogTitle>
                </DialogHeader>
                <div className="py-4">
                  <Input 
                    placeholder="Search users..." 
                    className="bg-black/50 border-white/10"
                    // Implement user search here if needed
                  />
                </div>
              </DialogContent>
            </Dialog>
          </div>

          <div className="p-3">
            <div className="relative">
              <Search className="absolute left-3 top-2.5 w-4 h-4 text-zinc-500" />
              <Input 
                placeholder={sidebarCopy.search_placeholder || "Search messages..."}
                className="pl-9 bg-black/20 border-white/5 focus:border-white/20 transition-all"
              />
            </div>
          </div>

          <div className="flex-1 overflow-y-auto">
            {loadingChats ? (
              <div className="flex justify-center p-8">
                <Loader2 className="w-6 h-6 text-zinc-500 animate-spin" />
              </div>
            ) : recentChats.length === 0 ? (
              <div className="text-center p-8 text-zinc-500 text-sm">
                {sidebarCopy.empty || "No conversations yet."}
              </div>
            ) : (
              <div className="space-y-1">
                {recentChats.map(chat => (
                  <div
                    key={chat.userId}
                    onClick={() => router.push(`/inbox/${chat.userId}`)}
                    className={cn(
                      "p-3 mx-2 rounded-xl cursor-pointer transition-colors flex gap-3 items-start",
                      targetUserId === chat.userId ? "bg-white/10" : "hover:bg-white/5"
                    )}
                  >
                    <div className="relative">
                        <Avatar>
                        <AvatarImage src={chat.avatarUrl || undefined} alt={chat.name} />
                        <AvatarFallback>{chat.name.substring(0, 2).toUpperCase()}</AvatarFallback>
                        </Avatar>
                        {chat.unreadCount > 0 && (
                            <span className="absolute -top-1 -right-1 w-4 h-4 bg-emerald-500 rounded-full flex items-center justify-center text-[10px] font-bold">
                                {chat.unreadCount}
                            </span>
                        )}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex justify-between items-baseline mb-0.5">
                        <span className="font-bold text-sm truncate">{chat.name}</span>
                        <span className="text-[10px] text-zinc-500 whitespace-nowrap ml-2">
                          {formatDistanceToNow(new Date(chat.lastMessageTime), { addSuffix: false })}
                        </span>
                      </div>
                      <p className={cn(
                          "text-xs truncate",
                          chat.unreadCount > 0 ? "text-white font-medium" : "text-zinc-400"
                      )}>
                        {chat.lastMessageType === 'image' ? 'ðŸ“· Image' : 
                         chat.lastMessageType === 'deal_update' ? 'âš¡ Deal Update' : 
                         chat.lastMessage}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Chat Area */}
        <div className={cn(
          "flex-1 flex flex-col bg-black",
          !targetUserId ? "hidden md:flex" : "flex"
        )}>
          {targetUserId && roomName ? (
            <RealtimeChat 
              roomName={roomName}
              userId={user.id}
              username={username}
              isVerified={isVerified}
              role={role}
              targetUser={targetUser || undefined}
            />
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center text-zinc-500">
              <MessageSquarePlus className="w-16 h-16 mb-4 opacity-20" />
              <h3 className="text-lg font-medium text-zinc-400">{chatCopy.placeholder_title || "Select a conversation"}</h3>
              <p className="text-sm">{chatCopy.placeholder_desc || "Choose a chat from the sidebar to start messaging."}</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

﻿"use client";

import dynamic from "next/dynamic";
import { useParams, useRouter } from "next/navigation";
import { useUser } from "@/contexts/UserContext";
import { useMessagesQuery } from "@/hooks/use-messages-query";
import { Navbar } from "@/components/app/navigation/Navbar";
import { Loader2 } from "lucide-react";
import { useEffect, useState, useMemo, useCallback } from "react";
import { createClient } from "@/lib/infra/supabase/supabase";
import { cn } from "@/lib/core/utils/utils";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/shared/ui/avatar";
import { formatDistanceToNow } from "date-fns";
import { it } from "date-fns/locale";

import { Input } from "@/components/shared/ui/input";
import { Button } from "@/components/shared/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/shared/ui/dialog";
import { Search, Plus, MessageSquarePlus, X } from "lucide-react";
import { toast } from "@/lib/domains/notifications";

const RealtimeChat = dynamic(
  () => import("@/components/features/realtime-chat/realtime-chat").then((mod) => mod.RealtimeChat),
  {
    ssr: false,
    loading: () => (
      <div className="flex h-full items-center justify-center text-sm text-zinc-500">
        Loading chat...
      </div>
    ),
  }
);

type FoundUser = {
  id: string;
  username: string | null;
  full_name: string | null;
  avatar_url: string | null;
};

type ChatMessageRecord = {
  room_id: string;
  content: string;
  created_at: string;
  sender_id: string;
  is_read: boolean;
  receiver_id?: string;
  type?: string;
  is_deleted?: boolean;
};

type CurrentUser = {
  id: string;
  email?: string | null;
  user_metadata?: {
    username?: string | null;
    full_name?: string | null;
    is_admin?: boolean;
    seller_status?: string | null;
  };
};

export default function ChatPage() {
  const params = useParams();
  // Get raw ID from URL path (e.g. /inbox/123 or /inbox/wallet)
  // If params.id is undefined, it means we are at /inbox root
  const rawUserId = params.id ? (Array.isArray(params.id) ? params.id[0] : params.id) : null;
  const [targetUserId, setTargetUserId] = useState<string | null>(null);
  const { user, isLoading } = useUser();
  const router = useRouter();
  const supabase = useMemo(() => createClient(), []);
  const [recentChats, setRecentChats] = useState<{ 
    userId: string, 
    name: string, 
    avatarUrl: string | null,
    lastMessage: string,
    lastMessageType: string, // Added to distinguish system messages
    lastMessageTime: string,
    unreadCount: number,
    deal?: {
      id: string,
      status: string,
      price: number,
      currency?: string,
      lastEvent?: string
    }
  }[]>([]);
  const [loadingChats, setLoadingChats] = useState(true);

  // Resolve rawUserId (UUID or Wallet) to targetUserId (UUID)
  useEffect(() => {
    async function resolveUser() {
        if (!rawUserId) {
            setTargetUserId(null);
            return;
        }

        // If it looks like a UUID, use it directly
        const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
        if (uuidRegex.test(rawUserId)) {
            setTargetUserId(rawUserId);
            return;
        }

        // Security hardening: do not resolve direct chats by wallet/payout address.
        setTargetUserId(null);
    }
    resolveUser();
  }, [rawUserId, supabase]);


  // New Chat Modal & Search Logic
  const [searchQuery, setSearchQuery] = useState("");
  const [isNewChatOpen, setIsNewChatOpen] = useState(false);
  const [searchUserQuery, setSearchUserQuery] = useState("");
  const [foundUsers, setFoundUsers] = useState<FoundUser[]>([]);
  const [searchingUsers, setSearchingUsers] = useState(false);

  const handleSearchUsers = async (query: string) => {
      setSearchUserQuery(query);
      if (query.length < 2) {
          setFoundUsers([]);
          return;
      }
      
      setSearchingUsers(true);
      try {
        const { data } = await supabase
            .from('profiles')
            .select('id, username, full_name, avatar_url')
            .or(`username.ilike.%${query}%,full_name.ilike.%${query}%`)
            .neq('id', user?.id) // Exclude self
            .limit(5);
            
        if (data) {
            setFoundUsers(data);
        }
      } catch (e) {
          console.error(e);
      } finally {
          setSearchingUsers(false);
      }
  };


  // Realtime subscription for updates
  useEffect(() => {
    if (!user) return;

    // Listen to changes in chat_messages table
    const channel = supabase
      .channel('inbox-updates')
      .on(
        'postgres_changes',
        {
          event: '*', // Listen to all events (INSERT, UPDATE)
          schema: 'public',
          table: 'chat_messages'
        },
        async (payload) => {
          console.log('Inbox Realtime Event:', payload);
          const newMessage = payload.new as ChatMessageRecord;
          const oldMessage = payload.old as ChatMessageRecord;
          const roomId = newMessage?.room_id || oldMessage?.room_id;
          
          if (!roomId || typeof roomId !== 'string') return;

          // Determine the other user ID from room ID
          const parts = roomId.split('_');
          const otherUserId = parts.find((id: string) => id !== user.id);
          const isMyRoom = parts.includes(user.id);
          
          if (!otherUserId || !isMyRoom) return;

          // Handle message deletion (soft delete)
          if (payload.eventType === 'UPDATE' && newMessage.is_deleted) {
              setRecentChats(prev => prev.filter(c => c.userId !== otherUserId));
              return;
          }

           // Show notification if it's an incoming message and we are NOT in this chat currently
           const isIncoming = newMessage?.sender_id !== user.id;
           const isCurrentChat = targetUserId === otherUserId;
           
           if (isIncoming && !isCurrentChat && payload.eventType === 'INSERT') {
               let senderName = 'Qualcuno';
               const { data: profile } = await supabase.from('profiles').select('full_name, username').eq('id', otherUserId).single();
               if (profile) senderName = profile.full_name || profile.username || 'Utente';

               toast.info({
                   title: senderName,
                   description: (
                     <div className="flex flex-col gap-1">
                       <span className="text-sm text-zinc-300 truncate max-w-[200px]">{newMessage.content}</span>
                     </div>
                   ),
                   action: {
                       label: 'Vedi',
                       onClick: () => router.push(`/inbox/${otherUserId}`)
                   }
               });
           }
 
           // Update list
           setRecentChats(prev => {
             const existingChatIndex = prev.findIndex(c => c.userId === otherUserId);
             
             if (existingChatIndex >= 0) {
               // Update existing chat
               const updatedChats = [...prev];
               const existingTime = new Date(updatedChats[existingChatIndex].lastMessageTime).getTime();
               const newTime = new Date(newMessage.created_at).getTime();
               
               if (newTime >= existingTime) {
                   updatedChats[existingChatIndex] = {
                     ...updatedChats[existingChatIndex],
                     lastMessage: newMessage.content,
                     lastMessageTime: newMessage.created_at,
                     // Increment unread count if it's incoming and we're not viewing it
                     unreadCount: (isIncoming && !isCurrentChat && payload.eventType === 'INSERT') 
                        ? updatedChats[existingChatIndex].unreadCount + 1 
                        : (payload.eventType === 'UPDATE' && newMessage.is_read) 
                            ? 0 
                            : updatedChats[existingChatIndex].unreadCount
                   };
                   // Move to top
                   updatedChats.sort((a, b) => new Date(b.lastMessageTime).getTime() - new Date(a.lastMessageTime).getTime());
                   return updatedChats;
               }
               return prev;
             }
             return prev;
           });

          // Check if it's a new chat (using functional state to avoid dependency)
          if (payload.eventType === 'INSERT') {
              setRecentChats(prev => {
                 const isInList = prev.some(c => c.userId === otherUserId);
                 if (!isInList) {
                    fetchProfileAndAdd(otherUserId, newMessage);
                 }
                 return prev;
              });
          }
        }
      )
      .subscribe();

    async function fetchProfileAndAdd(userId: string, message: ChatMessageRecord) {
        const { data: profile } = await supabase
            .from('profiles')
            .select('id, full_name, username, avatar_url')
            .eq('id', userId)
            .single();
            
        if (profile) {
            setRecentChats(prev => {
                if (prev.some(c => c.userId === userId)) return prev;
                
                const newChat = {
                    userId: profile.id,
                    name: profile.full_name || profile.username || 'Utente',
                    avatarUrl: profile.avatar_url,
                    lastMessage: message.content,
                    lastMessageType: message.type || 'text',
                    lastMessageTime: message.created_at,
                    unreadCount: message.sender_id !== user?.id ? 1 : 0
                };
                return [newChat, ...prev];
            });
        }
    }

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user, supabase, targetUserId]); // Added targetUserId to handle unread count updates correctly

  useEffect(() => {
    async function fetchRecentChats() {
      if (!user) return;
      setLoadingChats(true);
      try {
        // Fetch recent messages from DB to identify rooms and calculate unread counts
        const { data, error } = await supabase
          .from('chat_messages')
          .select('room_id, created_at, content, is_read, sender_id, type, is_deleted')
          .ilike('room_id', `%${user.id}%`)
          .eq('is_deleted', false)
          .order('created_at', { ascending: false });
        
        if (error) {
          console.error('Error listing chats:', error);
          setLoadingChats(false);
          return;
        }

        if (data) {
          const userIds = new Set<string>();
          const roomStats = new Map<string, { lastMessage: string, lastMessageType: string, lastTime: string, unreadCount: number }>();

          data.forEach(msg => {
             const parts = msg.room_id.split('_');
             const otherId = parts.find((id: string) => id !== user.id);
             if (!otherId) return;
             
             userIds.add(otherId);

             if (!roomStats.has(msg.room_id)) {
                roomStats.set(msg.room_id, { 
                  lastMessage: msg.content, 
                  lastMessageType: msg.type || 'text',
                  lastTime: msg.created_at,
                  unreadCount: 0 
                });
             }

             // Count unread if it's incoming and not read
             if (msg.sender_id !== user.id && !msg.is_read) {
                const stats = roomStats.get(msg.room_id)!;
                stats.unreadCount++;
             }
          });
          
          if (userIds.size > 0) {
              const { data: profiles } = await supabase
                .from('profiles')
                .select('id, full_name, username, avatar_url')
                .in('id', Array.from(userIds));

              // Fetch related deals
              const { data: deals } = await supabase
                .from('deals')
                .select(`
                  id, 
                  status, 
                  buyer_id, 
                  seller_id,
                  offers!inner(price)
                `)
                .or(`buyer_id.in.(${Array.from(userIds).map(id => `'${id}'`).join(',')}),seller_id.in.(${Array.from(userIds).map(id => `'${id}'`).join(',')})`)
                .order('created_at', { ascending: false });
                
              if (profiles) {
                  const chats = profiles.map(p => {
                      const roomId = [user.id, p.id].sort().join('_');
                      const stats = roomStats.get(roomId);
                      
                      const userDeal = deals?.find(d => 
                        (d.buyer_id === p.id && d.seller_id === user.id) || 
                        (d.seller_id === p.id && d.buyer_id === user.id)
                      );
                      
                      const offersData = (userDeal?.offers ?? null) as
                        | { price: number }
                        | Array<{ price: number }>
                        | null;
                      const dealPrice = Array.isArray(offersData)
                        ? (offersData[0]?.price ?? 0)
                        : (offersData?.price ?? 0);

                      return {
                          userId: p.id,
                          name: p.full_name || p.username || 'Utente',
                          avatarUrl: p.avatar_url,
                          lastMessage: stats?.lastMessage || '',
                          lastMessageType: stats?.lastMessageType || 'text',
                          lastMessageTime: stats?.lastTime || '',
                          unreadCount: stats?.unreadCount || 0,
                          deal: userDeal ? {
                            id: userDeal.id,
                            status: userDeal.status,
                            price: dealPrice,
                            currency: 'USDC'
                          } : undefined
                      };
                  });
                  
                  chats.sort((a, b) => new Date(b.lastMessageTime).getTime() - new Date(a.lastMessageTime).getTime());
                  setRecentChats(chats);
              }
          }
        }
      } catch (e) {
        console.error('Failed to fetch recent chats:', e);
      } finally {
        setLoadingChats(false);
      }
    }
    
    fetchRecentChats();
  }, [user, supabase]);

  useEffect(() => {
    if (targetUserId) {
      setRecentChats(prev => prev.map(chat => 
        chat.userId === targetUserId ? { ...chat, unreadCount: 0 } : chat
      ));
    }
  }, [targetUserId]);

  // Reset search when modal is toggled
  useEffect(() => {
      if (!isNewChatOpen) {
          setSearchUserQuery("");
          setFoundUsers([]);
