﻿"use client";

/* eslint-disable react-hooks/set-state-in-effect */
import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, CheckCircle2, DollarSign, ChevronRight } from "lucide-react";
import { Squircle } from "@/components/shared/ui/Squircle";
import { cn } from "@/lib/core/utils/utils";

interface OfferModalProps {
  isOpen: boolean;
  onClose: () => void;
  listingPrice: number;
  onSendOffer: (amount: number, message: string) => void;
  dealId?: string;
}

export function OfferModal({
  isOpen,
  onClose,
  listingPrice,
  onSendOffer,
  dealId
}: OfferModalProps) {
  const [step, setStep] = useState<"input" | "success">("input");
  const [offerAmount, setOfferAmount] = useState(listingPrice);
  const [message, setMessage] = useState("");
  const [sliderValue, setSliderValue] = useState(100); // Percentage 70-100

  // Reset state when modal opens
  useEffect(() => {
    if (isOpen) {
      setStep("input");
      setOfferAmount(listingPrice);
      setSliderValue(100);
      setMessage("");
    }
  }, [isOpen, listingPrice]);

  // Handle slider change
  const handleSliderChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const percent = parseInt(e.target.value);
    setSliderValue(percent);
    setOfferAmount(Math.round((listingPrice * percent) / 100));
  };

  // Handle input change
  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    // Remove non-numeric chars
    const val = e.target.value.replace(/[^0-9]/g, "");
    if (val) {
      const amount = parseInt(val);
      setOfferAmount(amount);
      // Update slider if within range, otherwise 100 or 70 (clamped visually or detached)
      const percent = Math.min(100, Math.max(70, Math.round((amount / listingPrice) * 100)));
      setSliderValue(percent);
    } else {
      setOfferAmount(0);
    }
  };

  const handleSend = () => {
    onSendOffer(offerAmount, message);
    setStep("success");
  };

  // Prevent body scroll
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "unset";
    }
    return () => {
      document.body.style.overflow = "unset";
    };
  }, [isOpen]);

  const savings = listingPrice - offerAmount;

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm"
          />

          {/* Modal Container */}
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            transition={{ duration: 0.2, ease: "easeOut" }}
            className="fixed left-1/2 top-1/2 z-50 w-full max-w-lg -translate-x-1/2 -translate-y-1/2 px-4"
          >
            <Squircle
              radius={24}
              smoothing={0.8}
              className="w-full shadow-2xl"
              innerClassName="bg-zinc-950 border border-white/10 overflow-hidden"
            >
              {/* Close Button */}
              <button
                onClick={onClose}
                className="absolute right-4 top-4 z-10 rounded-full p-2 text-zinc-400 hover:bg-white/5 hover:text-white transition-colors"
              >
                <X className="h-5 w-5" />
              </button>

              <div className="p-6 md:p-8">
                {step === "input" ? (
                  <div className="space-y-6">
                    {/* Header */}
                    <div className="text-center space-y-2">
                      <h2 className="text-2xl font-bold text-white">Send an Offer</h2>
                      <p className="text-zinc-400">Propose your price to the seller.</p>
                    </div>

                    {/* Price Input */}
                    <div className="relative">
                      <div className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-500">
                        <DollarSign className="h-6 w-6" />
                      </div>
                      <input
                        type="text"
                        value={offerAmount.toLocaleString()}
                        onChange={handleInputChange}
                        onKeyDown={(e) => {
                          if (e.key === "Enter") {
                            handleSend();
                          }
                        }}
                        className="w-full bg-zinc-900/50 border border-white/10 rounded-xl py-4 pl-12 pr-4 text-3xl font-bold text-white text-center focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500/50 transition-all"
                      />
                    </div>

                    {/* Slider */}
                    <div className="space-y-4">
                      <div className="flex justify-between text-xs font-medium text-zinc-500 uppercase tracking-wider">
                        <span>70%</span>
                        <span>Listing Price</span>
                      </div>
                      <div className="relative h-6 w-full flex items-center">
                        <input
                          type="range"
                          min="70"
                          max="100"
                          step="1"
                          value={sliderValue}
                          onChange={handleSliderChange}
                          className="w-full h-2 bg-zinc-800 rounded-lg appearance-none cursor-pointer accent-indigo-500 [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-6 [&::-webkit-slider-thumb]:h-6 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:shadow-lg [&::-webkit-slider-thumb]:cursor-pointer [&::-webkit-slider-thumb]:border-4 [&::-webkit-slider-thumb]:border-indigo-600 hover:[&::-webkit-slider-thumb]:scale-110 transition-all"
                        />
                        {/* Custom Track Overlay could be added here for gradient if needed, but accent-color works for basic modern browsers */}
                      </div>
                    </div>

                    {/* Offer Summary */}
                    <Squircle
                      radius={16}
                      smoothing={0.6}
                      className="w-full"
                      innerClassName="bg-indigo-500/10 border border-indigo-500/20 p-4"
                    >
                      <div className="flex justify-between items-center">
                        <div>
                          <p className="text-sm text-indigo-300 font-medium">Your Offer</p>
                          <p className="text-xl font-bold text-indigo-400">${offerAmount.toLocaleString()}</p>
                        </div>
                        {savings > 0 && (
                          <div className="text-right">
                            <p className="text-sm text-emerald-400 font-medium">You save</p>
                            <p className="text-lg font-bold text-emerald-500">${savings.toLocaleString()}</p>
                          </div>
                        )}
                        {savings <= 0 && (
                          <div className="text-right">
                            <p className="text-sm text-zinc-400 font-medium">Listing Price</p>
                            <p className="text-lg font-bold text-white">${listingPrice.toLocaleString()}</p>
                          </div>
                        )}
                      </div>
                    </Squircle>

                    {/* Message */}
                    <div className="space-y-2">
                      <label className="text-sm font-medium text-zinc-400">Message to Seller (optional)</label>
                      <textarea
                        value={message}
                        onChange={(e) => setMessage(e.target.value)}
                        onKeyDown={(e) => {
                          if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) {
                            handleSend();
                          }
                        }}
                        placeholder="Hi, would you accept this offer for a quick sale?"
                        className="w-full h-24 bg-zinc-900/50 border border-white/10 rounded-xl p-4 text-white placeholder:text-zinc-600 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500/50 resize-none transition-all text-sm"
                      />
                    </div>

                    {/* Actions */}
                    <div className="grid grid-cols-2 gap-3 pt-2">
                      <button
                        onClick={onClose}
                        className="w-full py-3 px-4 bg-zinc-800 hover:bg-zinc-700 text-white font-medium rounded-xl transition-all border border-white/5 active:scale-[0.98]"
                      >
                        Cancel
                      </button>
                      <button
                        onClick={handleSend}
                        className="w-full py-3 px-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all shadow-lg shadow-indigo-900/20 active:scale-[0.98]"
                      >
                        Send Offer
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="py-8 text-center space-y-6">
                    <div className="mx-auto h-20 w-20 bg-emerald-500/10 rounded-full flex items-center justify-center border border-emerald-500/20">
                      <CheckCircle2 className="h-10 w-10 text-emerald-500" />
                    </div>

                    <div className="space-y-2">
                      <h2 className="text-2xl font-bold text-white">Offer Sent Successfully</h2>
                      <p className="text-zinc-400">The seller will review your offer.</p>
                    </div>

                    <div className="space-y-3 pt-4">
                      <button
                        onClick={onClose}
                        className="w-full py-3 px-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all shadow-lg shadow-indigo-900/20 active:scale-[0.98]"
                      >
                        Continue Chat
                      </button>
                      <button
                        onClick={onClose} // Just close for now, logically "View Deal" keeps you on page
                        className="w-full py-3 px-4 bg-zinc-800 hover:bg-zinc-700 text-white font-medium rounded-xl transition-all border border-white/5 active:scale-[0.98]"
                      >
                        View Deal
                      </button>
                    </div>
                  </div>
                )}
              </div>
            </Squircle>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
}

﻿"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Copy, Check, ExternalLink, RefreshCw, AlertTriangle, ShieldCheck, Wallet } from "lucide-react";
import { Button } from "@/components/shared/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/shared/ui/card";
import { NETWORKS, CURRENCIES, getCurrenciesForNetwork, Network, Currency } from "@/lib/domains/payments/catalog";
import { createPaymentIntentAction, simulatePaymentDetection } from "@/app/(commerce)/deals/payment-actions"; // Adjust path if needed
import QRCode from "react-qr-code";
import { paymentsToast as toast } from "@/lib/domains/notifications";
import { cn } from "@/lib/core/utils/utils";

interface PaymentPanelProps {
  dealId: string;
  amount: number;
  isBuyer: boolean;
}

type PaymentIntentView = {
  deposit_address: string;
  pay_token_id: string;
};

export function PaymentPanel({ dealId, amount, isBuyer }: PaymentPanelProps) {
  const [step, setStep] = useState<"select" | "deposit" | "funded">("select");
  const [selectedNetwork, setSelectedNetwork] = useState<Network | null>(null);
  const [selectedCurrency, setSelectedCurrency] = useState<Currency | null>(null);
  const [paymentIntent, setPaymentIntent] = useState<PaymentIntentView | null>(null);
  const [loading, setLoading] = useState(false);
  const [copying, setCopying] = useState(false);

  // Poll for status simulation
  useEffect(() => {
    if (step === "deposit" && paymentIntent) {
      const interval = setInterval(() => {
        // In a real app, fetch status from server
        // For MVP demo, we rely on manual "Simulate" button or just check local state
      }, 5000);
      return () => clearInterval(interval);
    }
  }, [step, paymentIntent]);

  const handleCreateIntent = async () => {
    if (!selectedNetwork || !selectedCurrency) return;
    setLoading(true);

    try {
      // In a real app, dealId would be a UUID. For demo, we might use "d1".
      // The server action handles the mock fallback if DB insert fails.
      const result = await createPaymentIntentAction(dealId, selectedNetwork.id, selectedCurrency.id, amount);
      
      if (result.intent) {
        setPaymentIntent(result.intent as PaymentIntentView);
        setStep("deposit");
      } else {
        toast.error("Failed to create payment intent");
      }
    } catch (err) {
      console.error(err);
      toast.error("Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  const handleSimulatePayment = async () => {
    if (process.env.NODE_ENV !== "development") {
        toast.error("Simulation disabled in production");
        return;
    }
    setLoading(true);
    // Simulate detecting payment
    setTimeout(() => {
        setStep("funded");
        setLoading(false);
        toast.success("Payment Detected & Funded!");
    }, 2000);
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopying(true);
    setTimeout(() => setCopying(false), 2000);
    toast.success("Address copied");
  };

  if (step === "funded") {
    return (
      <Card className="bg-emerald-950/20 border-emerald-900/50 overflow-hidden">
        <CardContent className="p-6 text-center space-y-4">
            <div className="mx-auto h-16 w-16 rounded-full bg-emerald-500/20 flex items-center justify-center">
                <ShieldCheck className="h-8 w-8 text-emerald-500" />
            </div>
            <div>
                <h3 className="text-xl font-bold text-emerald-400">Funds Secured in Escrow</h3>
                <p className="text-emerald-200/60 text-sm mt-1">
                    Wait for the seller to fulfill the order.
                </p>
            </div>
             <div className="bg-emerald-900/20 p-3 rounded-lg text-xs font-mono text-emerald-300 break-all">
                Tx: 0x7f...3a2b (Confirmed)
            </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className="bg-zinc-900/40 border-zinc-800 overflow-hidden">
      <CardHeader className="pb-3 border-b border-zinc-800/50">
        <CardTitle className="flex items-center gap-2 text-base font-medium">
            <Wallet className="h-4 w-4 text-indigo-400" />
            Secure Payment (Escrow)
        </CardTitle>
      </CardHeader>
      
      <CardContent className="p-0">
        <AnimatePresence mode="wait">
            {step === "select" && (
                <motion.div
                    key="select"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="p-6 space-y-6"
                >
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <label className="text-sm font-medium text-zinc-400">Select Network</label>
                            <div className="grid grid-cols-2 gap-2">
                                {NETWORKS.map(net => (
                                    <button
                                        key={net.id}
                                        onClick={() => {
                                            setSelectedNetwork(net);
                                            setSelectedCurrency(null);
                                        }}
                                        className={cn(
                                            "flex flex-col items-start p-3 rounded-lg border text-left transition-all",
                                            selectedNetwork?.id === net.id
                                                ? "bg-indigo-600/10 border-indigo-500 text-indigo-100"
                                                : "bg-zinc-900 border-zinc-800 text-zinc-400 hover:border-zinc-700 hover:text-zinc-300"
                                        )}
                                    >
                                        <span className="font-semibold text-sm">{net.name}</span>
                                        <span className="text-xs opacity-70">{net.type}</span>
                                    </button>
                                ))}
                            </div>
                        </div>

                        {selectedNetwork && (
                            <div className="space-y-2 animate-in fade-in slide-in-from-top-2">
                                <label className="text-sm font-medium text-zinc-400">Select Token</label>
                                <div className="grid grid-cols-2 gap-2">
                                    {getCurrenciesForNetwork(selectedNetwork.id).map(curr => (
                                        <button
                                            key={curr.id}
                                            onClick={() => setSelectedCurrency(curr)}
                                            className={cn(
                                                "flex items-center justify-between p-3 rounded-lg border transition-all",
                                                selectedCurrency?.id === curr.id
                                                    ? "bg-indigo-600/10 border-indigo-500 text-indigo-100"
                                                    : "bg-zinc-900 border-zinc-800 text-zinc-400 hover:border-zinc-700 hover:text-zinc-300"
                                            )}
                                        >
                                            <span className="font-semibold text-sm">{curr.symbol}</span>
                                            {curr.isStablecoin && (
                                                <span className="text-[10px] bg-emerald-500/10 text-emerald-400 px-1.5 py-0.5 rounded">Stable</span>
                                            )}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    <Button 
                        onClick={handleCreateIntent}
                        disabled={!selectedNetwork || !selectedCurrency || loading}
                        className="w-full h-11 bg-white text-black hover:bg-zinc-200 font-medium"
                    >
                        {loading ? "Generating Address..." : `Pay $${amount} via ${selectedCurrency?.symbol || 'Crypto'}`}
                    </Button>
                </motion.div>
            )}

            {step === "deposit" && paymentIntent && (
                <motion.div
                    key="deposit"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    className="p-6 space-y-6"
                >
                    <div className="text-center space-y-2">
                        <div className="text-sm text-zinc-400 uppercase tracking-wider font-medium">Send exact amount</div>
                        <div className="text-3xl font-bold font-mono text-white tracking-tight">
                            {amount} <span className="text-indigo-400">{paymentIntent.pay_token_id}</span>
                        </div>
                         <div className="text-xs text-zinc-500 flex items-center justify-center gap-1">
                            on <span className="text-zinc-300 font-medium">{selectedNetwork?.name}</span> Network
                        </div>
                    </div>

                    <div className="flex justify-center bg-white p-4 rounded-xl w-fit mx-auto">
                        <QRCode value={paymentIntent.deposit_address} size={160} />
                    </div>

                    <div className="space-y-2">
                        <label className="text-xs font-medium text-zinc-500 uppercase">Deposit Address</label>
                        <div className="flex items-center gap-2">
                            <code className="flex-1 bg-zinc-950 p-3 rounded-lg text-xs font-mono text-zinc-300 break-all border border-zinc-800">
                                {paymentIntent.deposit_address}
                            </code>
                            <Button size="icon" variant="outline" className="shrink-0 border-zinc-700 text-zinc-400 hover:text-white" onClick={() => copyToClipboard(paymentIntent.deposit_address)}>
                                {copying ? <Check className="h-4 w-4" /> : <Copy className="h-4 w-4" />}
                            </Button>
                        </div>
                         <div className="flex items-center gap-2 text-xs text-yellow-500/80 bg-yellow-500/10 p-2 rounded border border-yellow-500/20">
                            <AlertTriangle className="h-3 w-3" />
                            <span>Only send {paymentIntent.pay_token_id} on {selectedNetwork?.name}.</span>
                        </div>
                    </div>

                    {/* Timeline */}
                    <div className="space-y-4 pt-4 border-t border-zinc-800">
                        <div className="flex items-center gap-3">
                            <div className="h-2 w-2 rounded-full bg-emerald-500 animate-pulse" />
                            <span className="text-sm text-zinc-300">Scanning blockchain...</span>
                        </div>
                        
                        <Button 
                            variant="secondary" 
                            className="w-full bg-zinc-800 hover:bg-zinc-700 text-zinc-300"
                            onClick={handleSimulatePayment}
                            disabled={loading}
                        >
                            {loading ? "Confirming..." : "Simulate Payment (Demo)"}
                        </Button>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
      </CardContent>
    </Card>
  );
}

﻿"use client";

