function BioText({ text, isOfficialProfile }: { text: string; isOfficialProfile: boolean }) {
  if (!text) return "No bio yet.";

  if (!isOfficialProfile) {
    return <>{text}</>;
  }

  // Regex migliorata per supportare domini come openlymarket.app anche senza http/www
  const linkRegex = /((?:https?:\/\/)?(?:www\.)?[a-zA-Z0-9-]+\.[a-zA-Z]{2,}(?:\/[^\s]*)?)/g;
  const parts = text.split(linkRegex);

  return (
    <>
      {parts.map((part, i) => {
        if (part.match(linkRegex)) {
           let href = part;
           if (!href.startsWith('http')) {
             href = `https://${href}`;
           }

           const isOpenlyMarketApp = part.toLowerCase().includes('openlymarket.app');

           return (
             <a 
               key={i} 
               href={href} 
               target="_blank" 
               rel="noopener noreferrer" 
               className={cn(
                 "hover:underline",
                 isOpenlyMarketApp ? "font-bold text-white" : "text-white"
               )}
               onClick={(e) => e.stopPropagation()}
             >
               {part}
             </a>
           );
        }
        return part;
      })}
    </>
  );
}


