        totalLifetimeOrders,
        last30DaysScore,
        isAdmin: dbProfile.is_admin === true,
        isVerifiedSeller: dbProfile.seller_status === "verified",
      });

      setPurchaseItems(purchases);
      setOfferItems(offers);
      setIsProfileLoading(false);
