"use client";

import { useRef, useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import type { TargetAndTransition } from 'framer-motion';

const BlurText = ({
  text = '',
  delay = 200,
  className = '',
  animateBy = 'words', // 'words' or 'letters'
  direction = 'top', // 'top' or 'bottom'
  threshold = 0.1,
  rootMargin = '0px',
  animationFrom,
  animationTo,
  easing = (t: number) => t,
  onAnimationComplete,
}: {
  text?: string;
  delay?: number;
  className?: string;
  animateBy?: 'words' | 'letters';
  direction?: 'top' | 'bottom';
  threshold?: number;
  rootMargin?: string;
  animationFrom?: TargetAndTransition;
  animationTo?: TargetAndTransition;
  easing?: (t: number) => number;
  onAnimationComplete?: () => void;
}) => {
  const elements = animateBy === 'words' ? text.split(' ') : text.split('');
  const [inView, setInView] = useState(false);
  const ref = useRef<HTMLParagraphElement>(null);
  const animatedCount = useRef(0);

  // Default animations based on direction
  const defaultFrom = direction === 'top'
    ? { filter: 'blur(10px)', opacity: 0, transform: 'translate3d(0,-50px,0)' }
    : { filter: 'blur(10px)', opacity: 0, transform: 'translate3d(0,50px,0)' };

  const defaultTo = {
    filter: 'blur(0px)',
    opacity: 1,
    transform: 'translate3d(0,0,0)',
  };

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setInView(true);
          if (ref.current) {
            observer.unobserve(ref.current);
          }
        }
      },
      { threshold, rootMargin }
    );

    if (ref.current) {
      observer.observe(ref.current);
    }

    return () => observer.disconnect();
  }, [threshold, rootMargin]);

  const springTransition = { type: 'spring' as const, damping: 20, stiffness: 100 };

  return (
    <p ref={ref} className={`flex flex-wrap ${className}`}>
      {elements.map((element, index) => (
        <motion.span
          key={index}
          initial={animationFrom || defaultFrom}
          animate={inView ? (animationTo || defaultTo) : (animationFrom || defaultFrom)}
          transition={{
            ...springTransition,
            delay: (index * delay) / 1000,
          }}
          onAnimationComplete={() => {
            animatedCount.current += 1;
            if (animatedCount.current === elements.length && onAnimationComplete) {
              onAnimationComplete();
            }
          }}
          className="inline-block will-change-transform will-change-filter will-change-opacity"
        >
          {element === ' ' ? '\u00A0' : element}
          {animateBy === 'words' && index < elements.length - 1 && '\u00A0'}
        </motion.span>
      ))}
    </p>
  );
};

export default BlurText;

﻿import { useEffect, useState } from 'react'
import { createClient } from '@/lib/infra/supabase/supabase'
import { ChatMessage } from '@/hooks/use-realtime-chat'

type MessageRow = {
  id: string
  content: string
  created_at: string
  sender_id: string
  type: 'text' | 'audio'
  metadata?: {
    user_snapshot?: { name?: string; isVerified?: boolean; role?: string }
    reactions?: Record<string, string[]>
    audioUrl?: string
    status?: 'sent' | 'read'
  } | null
  is_read: boolean
  is_deleted: boolean
  sender?: {
    full_name?: string | null
    username?: string | null
    seller_status?: string | null
    is_admin?: boolean | null
  } | null
}

export function useMessagesQuery(roomName: string) {
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const supabase = createClient()

  useEffect(() => {
    async function fetchMessages() {
      if (!roomName) return

      const { data, error } = await supabase
        .from('chat_messages')
        .select(`
          id,
          content,
          created_at,
          sender_id,
          type,
          metadata,
          is_read,
          is_deleted,
          sender:profiles(id, full_name, username, role_preference, seller_status, is_admin)
        `)
        .eq('room_id', roomName)
        .eq('is_deleted', false)
        .order('created_at', { ascending: true })

      if (error) {
        console.error('Error fetching messages from DB:', error)
        return
      }

      if (data) {
        const mappedMessages: ChatMessage[] = (data as MessageRow[]).map((msg) => {
          // Construct user object from profile join or metadata snapshot
          const profile = msg.sender
          const snapshot = msg.metadata?.user_snapshot

          const user = {
            id: msg.sender_id,
            name: profile?.full_name || profile?.username || snapshot?.name || 'Unknown User',
            isVerified: profile?.is_admin || profile?.seller_status === 'verified' || snapshot?.isVerified,
            role: profile?.is_admin ? 'Admin' : (profile?.seller_status === 'verified' ? 'Seller' : (snapshot?.role || 'User'))
          }

          return {
            id: msg.id,
            content: msg.content,
            user,
            createdAt: msg.created_at,
            reactions: msg.metadata?.reactions || {},
            type: msg.type as 'text' | 'audio',
            audioUrl: msg.metadata?.audioUrl,
            status: msg.is_read ? 'read' : 'sent'
          }
        })

        setMessages(mappedMessages)
      }
    }

    fetchMessages()
  }, [roomName])

  return { data: messages }
}

﻿import "server-only";
import { SITE_URL } from "@/lib/core/config/site-config";

const INDEXNOW_ENDPOINT = "https://api.indexnow.org/indexnow";
const BING_ENDPOINT = "https://www.bing.com/indexnow";
const BASE_URL = SITE_URL;
const INDEXNOW_KEY = process.env.INDEXNOW_KEY;

// URLs to never submit
const EXCLUDED_PREFIXES = [
  "/admin",
  "/api",
  "/auth",
  "/dashboard",
  "/install",
  "/onboarding",
  "/profile", // Usually private or requires auth
  "/track",
  "/deals", // Private transactional pages
  "/inbox",
  "/my-deals",
  "/settings",
];

function isPublicUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    if (parsed.hostname !== new URL(BASE_URL).hostname) return false;

    return !EXCLUDED_PREFIXES.some((prefix) => parsed.pathname.startsWith(prefix));
  } catch {
    return false;
  }
}

export async function submitToIndexNow(paths: string | string[]) {
  if (!INDEXNOW_KEY) {
    console.warn("âš ï¸ IndexNow key not configured. Skipping submission.");
    return;
  }

  if (process.env.NODE_ENV !== "production" && !process.env.INDEXNOW_DEBUG) {
    console.log("â„¹ï¸ IndexNow submission skipped in non-production environment.");
    return;
  }

  const urlList = Array.isArray(paths) ? paths : [paths];
  const publicUrls = urlList
    .map((path) => (path.startsWith("http") ? path : `${BASE_URL}${path.startsWith("/") ? "" : "/"}${path}`))
    .filter(isPublicUrl);

  if (publicUrls.length === 0) return;

  const payload = {
    host: new URL(BASE_URL).hostname,
    key: INDEXNOW_KEY,
    keyLocation: `${BASE_URL}/${INDEXNOW_KEY}.txt`,
    urlList: publicUrls,
  };

  try {
    // Submit to IndexNow (Microsoft/Bing) - they propagate to Yandex/others
    const res = await fetch(BING_ENDPOINT, {
      method: "POST",
      headers: {
        "Content-Type": "application/json; charset=utf-8",
      },
      body: JSON.stringify(payload),
    });

    if (!res.ok) {
      console.error(`âŒ IndexNow submission failed: ${res.status} ${res.statusText}`);
    } else {
      console.log(`âœ… IndexNow submitted ${publicUrls.length} URLs successfully.`);
    }
  } catch (error) {
    console.error("âŒ IndexNow submission error:", error);
  }
}

import { SignJWT, jwtVerify, type JWTPayload } from "jose";

const getSecretKey = () => {
  const secret = process.env.ADMIN_JWT_SECRET;
  if (!secret) {
    if (process.env.NODE_ENV === "production") {
      throw new Error("ADMIN_JWT_SECRET is missing in production environment");
    }
    return "dev-secret-do-not-use-in-prod";
  }
  return secret;
};

const getKey = () => new TextEncoder().encode(getSecretKey());

export async function signToken(payload: JWTPayload) {
  return await new SignJWT(payload)
    .setProtectedHeader({ alg: "HS256" })
    .setIssuedAt()
    .setExpirationTime("1h")
    .sign(getKey());
}

export async function verifyToken(token: string) {
  try {
    const { payload } = await jwtVerify(token, getKey());
    return payload;
  } catch (error) {
    return null;
  }
}

import * as cheerio from "cheerio";
import { ProductData, ProductParser } from "./types";

export class BaseParser implements ProductParser {
  canParse(url: string): boolean {
    return true; // Fallback parser handles everything
  }

  async parse(url: string, html: string): Promise<ProductData> {
    const $ = cheerio.load(html);
    const jsonLd = this.extractJsonLd($);
    const meta = this.extractMetaTags($);
    const fallbackPrice = this.extractPriceFallback(html);

    return {
      url,
      title: jsonLd.title || meta.title,
      image: this.absolutize(url, jsonLd.image || meta.image),
      description: jsonLd.description || meta.description,
      price: jsonLd.price || fallbackPrice.price,
      currency: jsonLd.currency || fallbackPrice.currency,
      siteName: meta.siteName || new URL(url).hostname,
    };
  }

  protected extractMetaTags($: cheerio.CheerioAPI) {
    const get = (selectors: string[]) => {
      for (const sel of selectors) {
        const val = $(sel).attr("content") || $(sel).attr("href");
        if (val && val.trim()) return val.trim();
      }
      return null;
    };

    return {
      title: get(['meta[property="og:title"]', 'meta[name="twitter:title"]']) || $("title").first().text().trim() || null,
      image: get(['meta[property="og:image"]', 'meta[name="twitter:image"]']),
      description: get(['meta[property="og:description"]', 'meta[name="twitter:description"]', 'meta[name="description"]']),
      siteName: get(['meta[property="og:site_name"]']),
    };
  }

  protected extractJsonLd($: cheerio.CheerioAPI): Partial<ProductData> {
    const scripts = $('script[type="application/ld+json"]')
      .map((_, el) => $(el).text())
      .get();

    for (const raw of scripts) {
      try {
        const parsed = JSON.parse(raw);
        const nodes = Array.isArray(parsed) ? parsed : [parsed];

        // Handle @graph structure
        const candidates = nodes.flatMap(n => n?.["@graph"] || n);

        for (const node of candidates) {
          if (node?.["@type"] === "Product") {
            const offers = Array.isArray(node.offers) ? node.offers[0] : node.offers;
            const price = offers?.price || offers?.lowPrice;
            const currency = offers?.priceCurrency;

            return {
              title: node.name,
              description: node.description,
              image: Array.isArray(node.image) ? node.image[0] : node.image,
              price: price ? Number(String(price).replace(/[^0-9.]/g, "")) : null,
              currency: currency || "USD",
            };
          }
        }
      } catch (e) {
        continue;
      }
    }
    return {};
  }

  protected extractPriceFallback(htmlText: string) {
    // Matches like $123.45, €99, 99.99 USD
    const symbolMatch = htmlText.match(/([$€£])\s?(\d{1,3}(?:[.,]\d{3})*(?:[.,]\d{2})?)/);
    if (symbolMatch) {
      const symbol = symbolMatch[1];
      const amount = parseFloat(symbolMatch[2].replace(/,/g, ""));
      return {
        price: isNaN(amount) ? null : amount,
        currency: symbol === "$" ? "USD" : symbol === "€" ? "EUR" : "GBP",
      };
    }

    const codeMatch = htmlText.match(/\b(\d{1,3}(?:[.,]\d{3})*(?:[.,]\d{2})?)\s?(USD|USDT|USDC|EUR|GBP)\b/i);
    if (codeMatch) {
      const amount = parseFloat(codeMatch[1].replace(/,/g, ""));
      return {
        price: isNaN(amount) ? null : amount,
        currency: codeMatch[2].toUpperCase(),
      };
    }

    return { price: null, currency: null };
  }

  protected absolutize(baseUrl: string, relativePath: string | null) {
    if (!relativePath) return null;
    try {
      return new URL(relativePath, baseUrl).toString();
    } catch {
      return null;
    }
  }
}

import { v4 as uuidv4 } from "uuid";
import { NETWORKS, CURRENCIES, Network, Currency } from "./catalog";

export interface PaymentIntent {
